'use client'
import { useState } from 'react'
import Link from 'next/link'
import Card from '../../../components/ui/Card'
import Badge from '../../../components/ui/Badge'
import Button from '../../../components/ui/Button'
import { FileText, ChevronRight, Search } from 'lucide-react'
import { BENEFIT_CATEGORIES } from '../../../lib/constants'

// Sample data — will come from API later
const schemes = [
  {
    id: 1,
    name: 'Disability Pension',
    category: 'pension' as const,
    description: 'Monthly pension for veterans with service-related disabilities.',
    is_eligible: true,
    required_documents: ['Discharge Certificate', 'Medical Certificate', 'Service Record'],
  },
  {
    id: 2,
    name: 'ECHS Medical Card',
    category: 'medical' as const,
    description: 'Ex-Servicemen Contributory Health Scheme medical coverage.',
    is_eligible: true,
    required_documents: ['Discharge Certificate', 'PPO', 'ID Proof'],
  },
  {
    id: 3,
    name: 'Education Scholarship',
    category: 'education' as const,
    description: 'Scholarship for children of veterans for higher education.',
    is_eligible: false,
    required_documents: ['Service Record', 'Child Birth Certificate', 'School/College ID'],
  },
  {
    id: 4,
    name: 'Housing Loan Subsidy',
    category: 'housing' as const,
    description: 'Subsidized home loans for ex-servicemen under government schemes.',
    is_eligible: true,
    required_documents: ['Discharge Certificate', 'Income Certificate', 'Land Documents'],
  },
  {
    id: 5,
    name: 'Resettlement Training',
    category: 'resettlement' as const,
    description: 'Free skill development and job placement assistance for veterans.',
    is_eligible: true,
    required_documents: ['Discharge Certificate', 'Service Record'],
  },
]

const categoryFilters = [
  { key: 'all',          label: 'All Schemes' },
  { key: 'pension',      label: 'Pension'     },
  { key: 'medical',      label: 'Medical'     },
  { key: 'education',    label: 'Education'   },
  { key: 'housing',      label: 'Housing'     },
  { key: 'resettlement', label: 'Resettlement'},
]

export default function BenefitsPage() {
  const [search,   setSearch]   = useState('')
  const [category, setCategory] = useState('all')

  const filtered = schemes.filter((s) => {
    const matchesSearch   = s.name.toLowerCase().includes(search.toLowerCase())
    const matchesCategory = category === 'all' || s.category === category
    return matchesSearch && matchesCategory
  })

  return (
    <div className="space-y-6">

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Benefit Schemes</h1>
          <p className="text-gray-500 text-sm mt-1">
            Browse and apply for available veteran benefit schemes
          </p>
        </div>
        <Link href="/benefits/apply">
          <Button variant="primary">Apply Now</Button>
        </Link>
      </div>

      {/* Search bar */}
      <div className="relative">
        <Search size={18} className="absolute left-3.5 top-3 text-gray-400" />
        <input
          type="text"
          placeholder="Search schemes..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-green-500 bg-white"
        />
      </div>

      {/* Category filters */}
      <div className="flex gap-2 flex-wrap">
        {categoryFilters.map((f) => (
          <button
            key={f.key}
            onClick={() => setCategory(f.key)}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all border ${
              category === f.key
                ? 'bg-green-700 text-white border-green-700'
                : 'bg-white text-gray-600 border-gray-200 hover:border-green-300'
            }`}
          >
            {f.label}
          </button>
        ))}
      </div>

      {/* Scheme cards */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {filtered.map((scheme) => {
          const catConfig = BENEFIT_CATEGORIES[scheme.category]
          return (
            <Card key={scheme.id} padding="md" hover>
              <div className="flex items-start justify-between mb-3">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-green-50 rounded-xl flex items-center justify-center">
                    <FileText size={20} className="text-green-700" />
                  </div>
                  <div>
                    <h3 className="font-semibold text-gray-900 text-sm">{scheme.name}</h3>
                    <Badge
                      label={catConfig.label}
                      color={catConfig.color as any}
                      size="sm"
                    />
                  </div>
                </div>
                <Badge
                  label={scheme.is_eligible ? 'Eligible' : 'Not Eligible'}
                  color={scheme.is_eligible ? 'green' : 'red'}
                  size="sm"
                />
              </div>

              <p className="text-sm text-gray-500 mb-4 leading-relaxed">
                {scheme.description}
              </p>

              <div className="mb-4">
                <p className="text-xs font-semibold text-gray-500 uppercase mb-2">
                  Required Documents
                </p>
                <div className="flex flex-wrap gap-1.5">
                  {scheme.required_documents.map((doc) => (
                    <span
                      key={doc}
                      className="px-2 py-0.5 bg-gray-100 text-gray-600 text-xs rounded-full"
                    >
                      {doc}
                    </span>
                  ))}
                </div>
              </div>

              <div className="flex gap-2">
                <Link href={`/benefits/${scheme.id}`} className="flex-1">
                  <Button variant="outline" size="sm" className="w-full">
                    View Details <ChevronRight size={14} className="ml-1" />
                  </Button>
                </Link>
                {scheme.is_eligible && (
                  <Link href="/benefits/apply">
                    <Button variant="primary" size="sm">Apply</Button>
                  </Link>
                )}
              </div>
            </Card>
          )
        })}
      </div>

      {filtered.length === 0 && (
        <div className="text-center py-12 text-gray-400">
          <FileText size={40} className="mx-auto mb-3 opacity-40" />
          <p>No schemes found matching your search.</p>
        </div>
      )}

    </div>
  )
}